void run_test(double r1, double i1, double r2, double i2) {
    ComplexNumber c1(r1, i1);
    ComplexNumber c2(r2, i2);
    ComplexNumber c3 = c1 + c2;

    std::ostringstream oss;
    oss << c3.getReal() << " " << c3.getImaginary();
    std::cout << oss.str() << std::endl;
}

